// Lista fixa de projetos para processar
const projetos = [
  { projeto_id: 741, nome: "Projeto Squad Labs" }
  // Adicione mais projetos aqui conforme necessário:
  // { projeto_id: 523, nome: "Outro Projeto" },
  // { projeto_id: 601, nome: "Mais um Projeto" }
];

console.log(`📋 Total de projetos a processar: ${projetos.length}`);

// Retorna cada projeto como um item separado
return projetos.map(projeto => ({
  json: projeto
}));

// Validação: verifica se recebeu dados válidos do WF2
if (!$json) {
  console.error('❌ ERRO: Nenhum dado recebido do WF2');
  throw new Error('WF2 não retornou dados');
}

// O WF2 retorna estruturas diferentes dependendo do caminho
// Extrair dados do formato correto
let relatorioHTML, projetoInfo, analise;

if ($json.html) {
  // Formato do montarHTMLRelatorio (sucesso)
  relatorioHTML = $json.html;
  projetoInfo = { 
    nome: $json.projeto_nome,
    id: null // não vem no output simplificado
  };
  analise = {
    concluidos: { total: $json.total_concluidos || 0 },
    em_andamento: { total: 0 },
    pendentes: { total: 0 },
    metricas: {
      total_horas_concluidas: 0,
      total_pontos_concluidos: 0
    }
  };
} else if ($json.projeto_info) {
  // Formato completo do WF2
  relatorioHTML = $json.html_relatorio || $json.relatorio_html;
  projetoInfo = $json.projeto_info;
  analise = $json.analise;
} else {
  console.error('❌ ERRO: Formato de dados não reconhecido');
  throw new Error('Formato inválido do WF2');
}

// Gera timestamp
const agora = new Date();
const dataFormatada = agora.toISOString().split('T')[0];
const horaFormatada = agora.toTimeString().split(' ')[0];

console.log(`📊 Relatório gerado para projeto ${projetoInfo.nome}`);
console.log(`   - Tamanho do HTML: ${relatorioHTML.length} caracteres`);

// Retorna objeto estruturado
return [{
  json: {
    projeto_nome: projetoInfo.nome,
    projeto_id: projetoInfo.id,
    data_geracao: dataFormatada,
    hora_geracao: horaFormatada,
    timestamp_completo: agora.toISOString(),
    relatorio_html: relatorioHTML,
    tamanho_html_bytes: relatorioHTML.length,
    assunto_email: $json.assunto || `Relatório Semanal - ${projetoInfo.nome} - ${dataFormatada}`
  }
}];

// Pega todos os relatórios gerados
const relatorios = $input.all();

console.log('');
console.log('========================================');
console.log('  EXECUÇÃO COMPLETA - RESUMO FINAL');
console.log('========================================');
console.log('');

// Extrai os dados reais (pode estar em .data ou direto no json)
const relatoriosExtraidos = relatorios.map(item => {
  // Se tem array "data", pega o primeiro item
  if (item.json.data && Array.isArray(item.json.data)) {
    return item.json.data[0];
  }
  return item.json;
});

const totalProjetos = relatoriosExtraidos.length;

console.log(`📊 Total de projetos processados: ${totalProjetos}`);
console.log('');

// Processa cada relatório
const resumoPorProjeto = relatoriosExtraidos.map((rel, index) => {
  console.log(`${index + 1}. Projeto: ${rel.projeto_nome || 'Desconhecido'}`);
  console.log(`   - ID: ${rel.projeto_id || 'N/A'}`);
  console.log(`   - Data: ${rel.data_geracao} ${rel.hora_geracao}`);
  console.log(`   - Tamanho HTML: ${(rel.tamanho_html_bytes / 1024).toFixed(2)} KB`);
  console.log(`   - Assunto Email: ${rel.assunto_email || 'N/A'}`);
  console.log('');

  return {
    projeto_id: rel.projeto_id,
    projeto_nome: rel.projeto_nome,
    data_geracao: rel.data_geracao,
    hora_geracao: rel.hora_geracao,
    tamanho_relatorio_kb: (rel.tamanho_html_bytes / 1024).toFixed(2),
    assunto_email: rel.assunto_email,
    tem_html: rel.relatorio_html ? true : false
  };
});

console.log('========================================');
console.log('✅ WORKFLOW CONCLUÍDO COM SUCESSO!');
console.log(`📧 ${totalProjetos} relatório(s) pronto(s) para envio`);
console.log('========================================');
console.log('');

// Retorna objeto final estruturado
return [{
  json: {
    execucao_completa: true,
    timestamp_execucao: new Date().toISOString(),

    totais: {
      projetos_processados: totalProjetos,
      relatorios_gerados: totalProjetos
    },

    relatorios: relatoriosExtraidos,

    resumo_por_projeto: resumoPorProjeto
  }
}];
